// Simulate client data lookup
const input = $json.body || $json;
const phone = input.phone || '';
const email = input.email || '';
const conversationId = input.conversation_id || '';

// Mock client database
const mockClients = {
  '+15551234567': {
    first_name: 'John',
    last_name: 'Smith',
    company: 'Acme Corp',
    account_type: 'Premium',
    loyalty_tier: 'Gold',
    last_interaction: 'Called 3 days ago about demo',
    notes: 'Prefers morning calls'
  },
  '+15559876543': {
    first_name: 'Jane',
    last_name: 'Doe',
    company: 'Tech Startup Inc',
    account_type: 'Standard',
    loyalty_tier: 'Silver',
    last_interaction: 'First-time caller',
    notes: ''
  },
  'john@acme.com': {
    first_name: 'John',
    last_name: 'Smith',
    company: 'Acme Corp',
    account_type: 'Premium',
    loyalty_tier: 'Gold',
    last_interaction: 'Called 3 days ago about demo',
    notes: 'Prefers morning calls'
  }
};

// Lookup by phone first, then email
let client = null;
let lookupKey = null;

if (phone && mockClients[phone]) {
  client = mockClients[phone];
  lookupKey = phone;
} else if (email && mockClients[email]) {
  client = mockClients[email];
  lookupKey = email;
}

if (client) {
  return {
    json: {
      success: true,
      client: client,
      cache_hit: true,
      lookup_key: lookupKey,
      latency_ms: Math.floor(Math.random() * 10) + 2,
      source: 'mock_database'
    }
  };
} else {
  return {
    json: {
      success: true,
      client: null,
      cache_hit: false,
      lookup_key: phone || email || 'none',
      latency_ms: Math.floor(Math.random() * 10) + 2,
      message: 'Client not found - new caller'
    }
  };
}
